sql_examples.sql:
SHOW PARAMETER FAST_START_MTTR_TARGET;

-- 또는
SELECT NAME, VALUE FROM V$PARAMETER WHERE NAME = 'fast_start_mttr_target';

-- 목표 복구 시간을 60초로 설정
ALTER SYSTEM SET FAST_START_MTTR_TARGET = 60 SCOPE=BOTH;

-- 자동 조정 모드로 전환
ALTER SYSTEM SET FAST_START_MTTR_TARGET = 0 SCOPE=BOTH;

SELECT CHECKPOINT_CHANGE#, CHECKPOINT_TIME FROM V$DATABASE;

-- 데이터 파일별 체크포인트 SCN 확인
SELECT FILE#, NAME, CHECKPOINT_CHANGE#, CHECKPOINT_TIME, STATUS FROM V$DATAFILE;

-- 수동 Full Checkpoint 실행
ALTER SYSTEM CHECKPOINT;

-- 수동 로그 스위치 실행 (Thread Checkpoint 발생)
ALTER SYSTEM SWITCH LOGFILE;

-- 아카이브 모드 확인
SELECT LOG_MODE FROM V$DATABASE;

-- 아카이브 로그 목록 및 상태 확인
ARCHIVE LOG LIST;

-- 아카이브 목적지 상태 확인
SELECT DEST_NAME, STATUS, DESTINATION, ARCHIVER FROM V$ARCHIVE_DEST WHERE STATUS != 'INACTIVE';

-- 그룹 상태 확인
SELECT GROUP#, THREAD#, SEQUENCE#, BYTES/1024/1024 AS "Size(MB)", MEMBERS, STATUS, ARCHIVED FROM V$LOG;

-- 멤버 상세 확인
SELECT GROUP#, STATUS, TYPE, MEMBER FROM V$LOGFILE ORDER BY GROUP#;

-- 현재 시스템 SCN 확인
SELECT CURRENT_SCN FROM V$DATABASE;

-- SCN과 타임스탬프 변환
SELECT SCN_TO_TIMESTAMP(CURRENT_SCN) AS CURRENT_TIME FROM V$DATABASE;

-- 데이터 파일 복구 필요 여부 확인
SELECT FILE#, NAME, STATUS, RECOVER, FUZZY FROM V$DATAFILE_HEADER WHERE RECOVER = 'YES' OR FUZZY = 'YES';
